+                return 'SUCCESS';
+            }
+
+            throw e;
+        }
+
+        throw Error('concat() did not revalidate the swapped element');
+    },
+
+    tests: [
+        { evil: {} },
+        { evil: "not a typed array" },
+        { evil: [0, 1, 2] },
+        { skip: () => !is_detach_available(), detach: true },
+    ],
+};
+
+
 let compare_tsuite = {
     name: "Buffer.compare() tests",
     skip: () => (!has_buffer()),
@@ -1069,6 +1122,7 @@ run([
